def select_pool(task: dict):
    if task["domain"] == "scrape":
        return "scraper_pool"
    elif task["domain"] == "code":
        return "code_pool"
    else:
        return "orchestrator_pool"

def route_request(task: dict):
    pool = select_pool(task)
    worker = select_worker(pool)

    if not is_healthy(worker):
        worker = select_healthy_worker(pool)
        if not worker:
            return fallback(task)  # fallback pool

    return send_to_worker(worker, task)
